        }
        else { result = nil }
        if let comp = self._diameter.value.isValueEqualOptionally(to: rhs._diameter.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._diameter_tolerance?.value.isValueEqualOptionally(to: rhs._diameter_tolerance?.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._placement.value.isValueEqualOptionally(to: rhs._placement.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        return result
      }


      //MARK: WHERE RULES (ENTITY)
      public static func WHERE_wr1(SELF: eEXPLICIT_ROUND_HOLE.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }

        let _TEMP1 /* eREPRESENTATION.PRef? */ = SELF.PLACEMENT?.GROUP_REF(eREPRESENTATION.self)
        let _TEMP2 /* SDAI.SET<eREPRESENTATION_ITEM.PRef>[1:(nil as SDAI.INTEGER?)] ? */ = _TEMP1?.ITEMS
        let _TEMP3 /* SDAI.SET<eREPRESENTATION_ITEM.PRef>[1:(nil as SDAI.INTEGER?)] ? */ = _TEMP2?
          .QUERY{ RI in 
            // QUERY BODY

            let _TEMP1 /* SDAI.LOGICAL */ = SDAI.TYPEOF( RI, IS: eAXIS2_PLACEMENT_3D.self )
            return _TEMP1
            // END QUERY BODY
          }
        let _TEMP4 /* SDAI.INTEGER? */ = SDAI.SIZEOF( _TEMP3 )
        let _TEMP5 /* SDAI.LOGICAL */ = _TEMP4 .==. SDAI.FORCE_OPTIONAL(SDAI.INTEGER(1))
        return _TEMP5
      }
