      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(
        DEPTH: ePOSITIVE_LENGTH_MEASURE_WITH_UNIT.PRef, 
        DEPTH_TOLERANCE: eTOLERANCE_VALUE.PRef? , 
        DIAMETER: ePOSITIVE_LENGTH_MEASURE_WITH_UNIT.PRef, 
        DIAMETER_TOLERANCE: sTOLERANCE_VALUE_OR_LIMITS_AND_FITS? , 
        PLACEMENT: eSHAPE_REPRESENTATION.PRef
      ) {

        self._depth = DEPTH
        self._depth_tolerance = DEPTH_TOLERANCE
        self._diameter = DIAMETER
        self._diameter_tolerance = DIAMETER_TOLERANCE
        self._placement = PLACEMENT

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( DEPTH: original._depth, DEPTH_TOLERANCE: original._depth_tolerance, DIAMETER: original._diameter, DIAMETER_TOLERANCE: original._diameter_tolerance, PLACEMENT: original._placement )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 5
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: 
          ePOSITIVE_LENGTH_MEASURE_WITH_UNIT.PRef.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]DEPTH for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverOptionalParameter(as: eTOLERANCE_VALUE.PRef.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]DEPTH_TOLERANCE for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p2) = exchangeStructure.recoverRequiredParameter(as: 
          ePOSITIVE_LENGTH_MEASURE_WITH_UNIT.PRef.self, from: parameters[2])
        else { exchangeStructure.add(errorContext: "while recovering parameter [2]DIAMETER for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p3) = exchangeStructure.recoverOptionalParameter(as: 
          sTOLERANCE_VALUE_OR_LIMITS_AND_FITS.self, from: parameters[3])
        else { exchangeStructure.add(errorContext: "while recovering parameter [3]DIAMETER_TOLERANCE for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p4) = exchangeStructure.recoverRequiredParameter(as: 
          eSHAPE_REPRESENTATION.PRef.self, from: parameters[4])
        else { exchangeStructure.add(errorContext: "while recovering parameter [4]PLACEMENT for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( DEPTH: p0, DEPTH_TOLERANCE: p1, DIAMETER: p2, DIAMETER_TOLERANCE: p3, PLACEMENT: p4 )
      }
